        import sailpoint.object.Identity; 
        import sailpoint.object.Custom; 
        import sailpoint.tools.Util; 
        
        addMessage(wfcontext, "Triggered Enable subprocess to enable accounts");
        trace(logName, "Ascension-Subprocess-Enable-User started for identity - " + identityName);
        trace(logName, "Entering Step: "+wfcontext.getStep().getName());
        
        //set ifMatchingADAccountExists value to false
        workflow.put("ifMatchingADAccountExists", false);

        Identity identity = context.getObjectByName(Identity.class, identityName);

        //set inactive to false
        identity.setAttribute("inactive", "false");

        //set maunalterm to NO 
        identity.setAttribute("manualTerm", "No");

        context.startTransaction();
        context.saveObject(identity);
        context.commitTransaction();    
        //comment decache //context.decache(identity);
        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

      
        trace(logName, "Entering Step: "+wfcontext.getStep().getName());
        String idSamAccountName = findSamAccountNameForIdentity(identityName);
        
        debug(logName, "SamAccountName for the identity: " + idSamAccountName);

        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
        return idSamAccountName;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

        import sailpoint.object.Identity; 
        trace(logName, "Entering Step: "+wfcontext.getStep().getName());

        List adAccountsList = new ArrayList();
        List serviceNowAccountsList = new ArrayList();

        boolean ifMatchingADAccountExists = false;

        Map rehireAccountsMap = new HashMap();
        List potentialAccountsList = new ArrayList();

        String domainValue = "";

        identityObject = context.getObjectByName(Identity.class, identityName);
        
        if(!isPeopleSoftUser(identityName)){
        domainValue = identityObject.getAttribute("domain");
        }

        rehireAccountsMap = findPotentialAccountsForRehire(identityName, domainValue); 


        if(rehireAccountsMap != null){
        potentialAccountsList = rehireAccountsMap.get("potentialAccountsList");
        addMessage(wfcontext, "Potential Accounts For Rehire: " + potentialAccountsList);
        debug(logName, "potentialAccountsList: " + potentialAccountsList);
        }

        if(potentialAccountsList != null){
        for(String potentialAccount: potentialAccountsList){

        if(potentialAccount.startsWith("AD-")){

        adAccountsList.add(potentialAccount.split(":")[1]);
        ifMatchingADAccountExists = true ; 

        }else if(potentialAccount.startsWith("ServiceNow")){

        serviceNowAccountsList.add(potentialAccount.split(":")[1]) ;
        }
        }
        }

        Map matchingAccounts = new HashMap();

        if(null != adAccountsList){
        matchingAccounts.put("AD accounts", adAccountsList);
        }
        if(null != serviceNowAccountsList){
        matchingAccounts.put("ServiceNow accounts", serviceNowAccountsList);
        }

        if(null != matchingAccounts){
        workflow.put("matchingAccounts", matchingAccounts);
        }

        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());
        return ifMatchingADAccountExists;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

        trace(logName, "Entering Step: "+wfcontext.getStep().getName());
        //isInMinistriesList method checks if the identity is in the persona enabled ministry
        boolean isInPersonaEnabledMinistry = isInMinistriesList(identityName);

        //Fetching the details to present in the workitem for Non-Persona Enabled Ministry
        if(!isInPersonaEnabledMinistry){

        addMessage(wfcontext, "Created workitem for review. WorkItem Name: Rehire - Manual Action Required for user : " + identityDisplayName + " [" + identityName + "]");
        
        updateIdentityAttributesForRehire(identityName);
        
        String reason = getReasonForNonPersonaManualAction(idSamAccountName, ifMatchingADAccountExists);

        //Add the reason for the workitem
        String wokitemName = setWorkItemNameForNonPersonaManualAction(reason, conversionType);
        workflow.put("rehireTypeDetails", wokitemName);
        
        //add audit for Non-Persona Manual Action workitem
        String auditString1 = "Non Persona User" + " - " + identityName + " - " + reason;
        String auditString2 = "Non-Persona Manual Action workitem is generated";
        String auditString3 = "Conversion type of the identity: " + conversionType;
        writeAuditRecordToIIQ("PersonaRehire", auditString1, auditString2, auditString3, identityName, "Persona Rehire");

        }
        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

        return isInPersonaEnabledMinistry;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;

        trace(logName, "Entering Step: "+wfcontext.getStep().getName());

        ProvisioningPlan plan = new ProvisioningPlan();
        
        if(null != identityName){   

        identityObject = context.getObjectByName(Identity.class, identityName);

        Map matchingAccounts = workflow.get("matchingAccounts");

        Map outputMap = enableAccount(identityName, matchingAccounts);
        Map displayNamesOfEnabledAccounts = outputMap.get("displayNamesOfEnabledAccounts");
        
        List displayNamesofAD = displayNamesOfEnabledAccounts.get("AD Accounts");
        List displayNamesofSNow = displayNamesOfEnabledAccounts.get("ServiceNow Accounts");

        String auditString1 = "Accounts for Reenable";
        String auditString2 = null; 
        String auditString3 = null;
        if(displayNamesofAD != null && !Util.isEmpty(displayNamesofAD)){
        auditString2 = "AD Accounts=" + String.join(",", displayNamesofAD);
        } else{
        auditString2 = "AD Accounts=Not Available";
        }
        if(displayNamesofSNow != null && !Util.isEmpty(displayNamesofSNow)){
        auditString3 = "ServiceNow Accounts=" + String.join(",", displayNamesofSNow);
        } else{
        auditString3 = "ServiceNow Accounts=Not Available";
        }
        writeAuditRecordToIIQ("PersonaRehire", auditString1, auditString2, auditString3, identityName, "Persona Rehire");

        addMessage(wfcontext, auditString1 + " : " + auditString2 + " " + auditString3);

        List accReqs = outputMap.get("accReqs");
        temporaryPassword = outputMap.get("password");

        workflow.put("temporaryPassword", temporaryPassword);

        List iiqAccReqList = assignRole(identityName);

        if(null != iiqAccReqList){

        ProvisioningPlan.AccountRequest iiqAcctReq = iiqAccReqList.get(0);

        iiqAcctReq.add(new AttributeRequest("inactive", ProvisioningPlan.Operation.Set, false));
        iiqAcctReq.add(new AttributeRequest("leaverDate", ProvisioningPlan.Operation.Set, ""));

        accReqs.add(iiqAcctReq);

        }

        plan.setAccountRequests(accReqs);
        
        if(null != identityObject){
        plan.setIdentity(identityObject);
        //comment decache //context.decache(identityObject);

        }
        debug(logName, "Final Plan in Rehire workflow  "+plan.toXml());
        //comment decache //context.decache(identityObject);
        }

        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

        return plan;

if(wfcase.hasErrors()){
workflow.put("stepName" , wfcontext.getStep().getName());
return true;
} else{
return false;
}

        import sailpoint.api.SailPointContext;
        import sailpoint.object.Identity;
        import sailpoint.object.ProvisioningPlan;
        import sailpoint.object.ProvisioningPlan.AccountRequest;
        import sailpoint.object.ProvisioningPlan.AttributeRequest;

        trace(logName, "Entering Step: "+wfcontext.getStep().getName());

        ProvisioningPlan plan = new ProvisioningPlan();
        
        if(null !=identityName){   

        identityObject = context.getObjectByName(Identity.class, identityName);
        
        //This logic to call the enable account method is to handle any disabled ServiceNow accounts

        Map matchingAccounts = workflow.get("matchingAccounts");
        
        List accReqs = new ArrayList();

        Map outputMap = enableAccount(identityName, matchingAccounts);
        accReqs = outputMap.get("accReqs");


        List iiqAccReqList = assignRole(identityName);

        if(null != iiqAccReqList){

        ProvisioningPlan.AccountRequest iiqAcctReq = iiqAccReqList.get(0);

        iiqAcctReq.add(new AttributeRequest("inactive", ProvisioningPlan.Operation.Set, false));
        iiqAcctReq.add(new AttributeRequest("leaverDate", ProvisioningPlan.Operation.Set, ""));

        accReqs.add(iiqAcctReq);
        
        String auditString1 = "Accounts for Creation";
        String auditString2 = null;
        String auditString3 = null;
        String domainValue = identityObject.getAttribute("domain");
        if((idSamAccountName != null && !Util.isEmpty(idSamAccountName)) && (domainValue != null && !Util.isEmpty(domainValue))){
        String displayNameConstruct = domainValue + "\\" + idSamAccountName;
        auditString2 = "AD Accounts=AD-AMITA: " + displayNameConstruct;
        auditString3 = "ServiceNow Accounts=ServiceNow: " + displayNameConstruct;
        } else{
        auditString2 = "AD Accounts=Not Available";
        auditString3 = "ServiceNow Accounts=Not Available";
        }
        writeAuditRecordToIIQ("PersonaRehire", auditString1, auditString2, auditString3, identityName, "Persona Rehire");

        addMessage(wfcontext, auditString1 + " : " + auditString2 + " " + auditString3);
        }

        plan.setAccountRequests(accReqs);
        
        if(null != identityObject){
        plan.setIdentity(identityObject);
        //comment decache //context.decache(identityObject);

        }
        debug(logName, "Final Plan in Rehire workflow  "+plan.toXml());
        //comment decache //context.decache(identityObject);
        }

        trace(logName, "Exiting Step: "+wfcontext.getStep().getName());

        return plan;

